@dataclass
class Dependency:
    """Represents a single Python dependency."""
    name: str
    version: str
    hashes: List[str] = field(default_factory=list)
    is_direct: bool = False
    extras: List[str] = field(default_factory=list)
    markers: Optional[str] = None
    source: Optional[str] = None

    @property
    def pinned_spec(self) -> str:
        """Return the pinned version specifier, e.g. 'requests==2.31.0'."""
        extras_str = f"[{','.join(self.extras)}]" if self.extras else ""
        spec = f"{self.name}{extras_str}=={self.version}"
        if self.markers:
            spec += f" ; {self.markers}"
        return spec

    @property
    def spec_with_hashes(self) -> str:
        """Return the pinned spec including hash lines for pip verification."""
        lines = [self.pinned_spec]
        for h in self.hashes:
            lines.append(f"    --hash={h}")
        return " \\\n".join(lines)


@dataclass
class LockFile:
    """Represents the full lock file state."""
    dependencies: Dict[str, Dependency] = field(default_factory=dict)
    python_version: str = ""
    platform: str = ""
    generated_at: str = ""
    strategy: str = ""

    def add(self, dep: Dependency):
        self.dependencies[dep.name.lower()] = dep

    def get(self, name: str) -> Optional[Dependency]:
        return self.dependencies.get(name.lower())

    def remove(self, name: str):
        self.dependencies.pop(name.lower(), None)

    @property
    def sorted_deps(self) -> List[Dependency]:
        return sorted(self.dependencies.values(), key=lambda d: d.name.lower())


@dataclass
class ProjectConfig:
    """Project-level dependency management configuration."""
    strategy: Strategy = Strategy.PIP_TOOLS
    python_requires: str = ">=3.9"
    source_files: Dict[str, str] = field(default_factory=lambda: {
        "prod": "requirements/prod.in",
        "dev": "requirements/dev.in",
        "test": "requirements/test.in",
    })
    lock_files: Dict[str, str] = field(default_factory=lambda: {
        "prod": "requirements/prod.txt",
        "dev": "requirements/dev.txt",
        "test": "requirements/test.txt",
    })
    include_hashes: bool = True
    allow_prereleases: bool = False
    trusted_hosts: List[str] = field(default_factory=list)
    extra_index_urls: List[str] = field(default_factory=list)
    ignored_packages: List[str] = field(default_factory=list)

    def save(self, path: str = CONFIG_FILE):
        """Persist configuration to a JSON file."""
        data = {
            "strategy": self.strategy.value,
            "python_requires": self.python_requires,
            "source_files": self.source_files,
            "lock_files": self.lock_files,
            "include_hashes": self.include_hashes,
            "allow_prereleases": self.allow_prereleases,
            "trusted_hosts": self.trusted_hosts,
            "extra_index_urls": self.extra_index_urls,
            "ignored_packages": self.ignored_packages,
        }
        with open(path, "w") as fh:
            json.dump(data, fh, indent=2)
        logger.info("Configuration saved to %s", path)

    @classmethod
    def load(cls, path: str = CONFIG_FILE) -> "ProjectConfig":
        """Load configuration from a JSON file."""
        if not os.path.exists(path):
            logger.warning("No config file found at %s – using defaults", path)
            return cls()
        with open(path) as fh:
            data = json.load(fh)
        return cls(
            strategy=Strategy(data.get("strategy", "pip-tools")),
            python_requires=data.get("python_requires", ">=3.9"),
            source_files=data.get("source_files", {}),
            lock_files=data.get("lock_files", {}),
            include_hashes=data.get("include_hashes", True),
            allow_prereleases=data.get("allow_prereleases", False),
            trusted_hosts=data.get("trusted_hosts", []),
            extra_index_urls=data.get("extra_index_urls", []),
            ignored_packages=data.get("ignored_packages", []),
        )


