def run_command(
    cmd: List[str],
    capture: bool = True,
    check: bool = True,
    env: Optional[dict] = None,
) -> subprocess.CompletedProcess:
    """Run a shell command and return the result."""
    logger.debug("Running: %s", " ".join(cmd))
    merged_env = {**os.environ, **(env or {})}
    result = subprocess.run(
        cmd,
        capture_output=capture,
        text=True,
        check=False,
        env=merged_env,
    )
    if check and result.returncode != 0:
        logger.error("Command failed: %s", " ".join(cmd))
        logger.error("STDOUT: %s", result.stdout)
        logger.error("STDERR: %s", result.stderr)
        raise RuntimeError(f"Command failed with exit code {result.returncode}")
    return result


def tool_available(name: str) -> bool:
    """Check whether a CLI tool is available on PATH."""
    return shutil.which(name) is not None


def compute_file_hash(filepath: str, algorithm: str = "sha256") -> str:
    """Compute the hash of a file."""
    h = hashlib.new(algorithm)
    with open(filepath, "rb") as fh:
        for chunk in iter(lambda: fh.read(8192), b""):
            h.update(chunk)
    return f"{algorithm}:{h.hexdigest()}"


def get_python_info() -> Tuple[str, str]:
    """Return (python_version, platform) strings."""
    import platform as plat
    return sys.version.split()[0], plat.platform()


def parse_requirements_txt(filepath: str) -> LockFile:
    """Parse a pip requirements.txt (with optional hashes) into a LockFile."""
    lock = LockFile()
    if not os.path.exists(filepath):
        return lock

    with open(filepath) as fh:
        content = fh.read()

    # Join continuation lines
    content = re.sub(r"\\\s*\n", " ", content)

    for line in content.splitlines():
        line = line.strip()
        if not line or line.startswith("#") or line.startswith("-"):
            continue

        # Extract hashes
        hashes = re.findall(r"--hash=(\S+)", line)
        line_clean = re.sub(r"\s*--hash=\S+", "", line).strip()

        # Extract markers
        markers = None
        if ";" in line_clean:
            line_clean, markers = line_clean.rsplit(";", 1)
            line_clean = line_clean.strip()
            markers = markers.strip()

        # Extract extras
        extras = []
        extras_match = re.search(r"\[([^\]]+)\]", line_clean)
        if extras_match:
            extras = [e.strip() for e in extras_match.group(1).split(",")]
            line_clean = re.sub(r"\[([^\]]+)\]", "", line_clean)

        # Split name==version
        match = re.match(r"^([A-Za-z0-9_.-]+)\s*==\s*([^\s;]+)", line_clean)
        if match:
            dep = Dependency(
                name=match.group(1),
                version=match.group(2),
                hashes=hashes,
                extras=extras,
                markers=markers,
            )
            lock.add(dep)

    return lock


def write_requirements_txt(lock: LockFile, filepath: str, include_hashes: bool = True):
    """Write a LockFile to a pip requirements.txt file."""
    python_version, platform = get_python_info()
    header = LOCK_FILE_HEADER.format(
        timestamp=datetime.utcnow().isoformat() + "Z",
        python_version=python_version,
        platform=platform,
    )
    os.makedirs(os.path.dirname(filepath) or ".", exist_ok=True)
    with open(filepath, "w") as fh:
        fh.write(header)
        for dep in lock.sorted_deps:
            if include_hashes and dep.hashes:
                fh.write(dep.spec_with_hashes + "\n")
            else:
                fh.write(dep.pinned_spec + "\n")
    logger.info("Lock file written: %s (%d packages)", filepath, len(lock.dependencies))


