# Strategy: pip-tools  (requirements.in -> pip-compile -> requirements.txt)
# ---------------------------------------------------------------------------

class PipToolsManager:
    """
    Manages dependencies using pip-tools (pip-compile / pip-sync).

    Workflow:
        1. Maintain human-edited .in files with direct dependencies.
        2. Run pip-compile to resolve and lock all transitive dependencies
           into .txt files with hashes.
        3. Run pip-sync to install exactly what is in the lock file.

    Directory layout:
        requirements/
            prod.in          # direct production dependencies
            dev.in           # -c prod.txt  + dev-only deps
            test.in          # -c prod.txt  + test-only deps
            prod.txt         # locked (auto-generated)
            dev.txt          # locked (auto-generated)
            test.txt         # locked (auto-generated)
    """

    def __init__(self, config: ProjectConfig):
        self.config = config

    def ensure_tools(self):
        """Ensure pip-tools is installed."""
        if not tool_available("pip-compile"):
            logger.info("pip-tools not found – installing...")
            run_command([sys.executable, "-m", "pip", "install", "pip-tools"])

    def compile(self, env_name: str = "prod", upgrade: bool = False,
                upgrade_package: Optional[str] = None):
        """
        Run pip-compile for a specific environment.

        Args:
            env_name: Which environment group to compile (prod, dev, test).
            upgrade: If True, upgrade all packages to latest allowed versions.
            upgrade_package: If set, upgrade only this specific package.
        """
        self.ensure_tools()

        source = self.config.source_files.get(env_name)
        output = self.config.lock_files.get(env_name)

        if not source or not output:
            raise ValueError(f"No source/lock file configured for env '{env_name}'")

        if not os.path.exists(source):
            raise FileNotFoundError(
                f"Source file {source} not found. Create it with your direct dependencies."
            )

        cmd = [
            "pip-compile",
            "--strip-extras",
            "--no-header",
            "--annotation-style=line",
            "--output-file", output,
        ]

        if self.config.include_hashes:
            cmd.append("--generate-hashes")

        if self.config.allow_prereleases:
            cmd.append("--pre")

        if upgrade:
            cmd.append("--upgrade")

        if upgrade_package:
            cmd.extend(["--upgrade-package", upgrade_package])

        for url in self.config.extra_index_urls:
            cmd.extend(["--extra-index-url", url])

        for host in self.config.trusted_hosts:
            cmd.extend(["--trusted-host", host])

        cmd.append(source)

        logger.info("Compiling %s -> %s", source, output)
        run_command(cmd, capture=False)
        logger.info("✅  Lock file generated: %s", output)

    def compile_all(self, upgrade: bool = False):
        """Compile lock files for all configured environments."""
        # Compile prod first (dev/test may constrain against it)
        order = ["prod", "dev", "test"]
        for env_name in order:
            if env_name in self.config.source_files:
                self.compile(env_name, upgrade=upgrade)

    def sync(self, env_name: str = "dev"):
        """
        Install exactly the packages in the lock file (pip-sync).

        This removes packages not listed in the lock file, ensuring a clean
        environment.
        """
        self.ensure_tools()
        lock_file = self.config.lock_files.get(env_name)
        if not lock_file or not os.path.exists(lock_file):
            raise FileNotFoundError(f"Lock file not found for env '{env_name}'")

        # For dev, sync both prod and dev
        files_to_sync = []
        if env_name in ("dev", "test"):
            prod_lock = self.config.lock_files.get("prod")
            if prod_lock and os.path.exists(prod_lock):
                files_to_sync.append(prod_lock)
        files_to_sync.append(lock_file)

        cmd = ["pip-sync"] + files_to_sync
        logger.info("Syncing environment to match: %s", ", ".join(files_to_sync))
        run_command(cmd, capture=False)
        logger.info("✅  Environment synced for '%s'", env_name)

    def verify(self, env_name: str = "prod") -> bool:
        """Verify that installed packages match the lock file."""
        lock_file = self.config.lock_files.get(env_name)
        if not lock_file or not os.path.exists(lock_file):
            logger.error("Lock file not found: %s", lock_file)
            return False

        lock = parse_requirements_txt(lock_file)
        result = run_command(
            [sys.executable, "-m", "pip", "list", "--format=json"],
            check=True,
        )
        installed = {
            pkg["name"].lower(): pkg["version"]
            for pkg in json.loads(result.stdout)
        }

        mismatches = []
        missing = []
        for dep in lock.sorted_deps:
            name_lower = dep.name.lower()
            if name_lower in self.config.ignored_packages:
                continue
            if name_lower not in installed:
                missing.append(dep)
            elif installed[name_lower] != dep.version:
                mismatches.append(
                    (dep.name, dep.version, installed[name_lower])
                )

        if missing:
            logger.warning("Missing packages:")
            for dep in missing:
                logger.warning("  - %s==%s", dep.name, dep.version)
        if mismatches:
            logger.warning("Version mismatches:")
            for name, expected, actual in mismatches:
                logger.warning(
                    "  - %s: expected %s, installed %s", name, expected, actual
                )

        if not missing and not mismatches:
            logger.info("✅  All packages match the lock file.")
            return True

        logger.error("❌  Dependency verification failed.")
        return False


