class PoetryManager:
    """
    Manages dependencies using Poetry (pyproject.toml / poetry.lock).

    Workflow:
        1. Define dependencies in pyproject.toml under [tool.poetry.dependencies]
           and [tool.poetry.group.dev.dependencies], etc.
        2. Run `poetry lock` to resolve and generate poetry.lock.
        3. Run `poetry install` to install from the lock file.
    """

    def __init__(self, config: ProjectConfig):
        self.config = config

    def ensure_tools(self):
        if not tool_available("poetry"):
            logger.error(
                "Poetry is not installed. Install it via:\n"
                "  curl -sSL https://install.python-poetry.org | python3 -\n"
                "  or: pipx install poetry"
            )
            raise RuntimeError("Poetry not found on PATH")

    def lock(self, update: bool = False):
        """Generate or update poetry.lock."""
        self.ensure_tools()
        cmd = ["poetry", "lock"]
        if not update:
            cmd.append("--no-update")
        logger.info("Running: %s", " ".join(cmd))
        run_command(cmd, capture=False)
        logger.info("✅  poetry.lock generated/updated")

    def install(self, env_name: str = "dev"):
        """Install dependencies from poetry.lock."""
        self.ensure_tools()
        cmd = ["poetry", "install"]
        if env_name == "prod":
            cmd.extend(["--only", "main"])
        elif env_name == "test":
            cmd.extend(["--with", "test"])
        else:
            # dev: install everything
            pass
        logger.info("Installing for env '%s': %s", env_name, " ".join(cmd))
        run_command(cmd, capture=False)
        logger.info("✅  Dependencies installed for '%s'", env_name)

    def update(self, package: Optional[str] = None):
        """Update dependencies."""
        self.ensure_tools()
        cmd = ["poetry", "update"]
        if package:
            cmd.append(package)
        run_command(cmd, capture=False)
        logger.info("✅  Dependencies updated")

    def export_requirements(self, output: str = "requirements.txt",
                            include_hashes: bool = True,
                            env_name: str = "prod"):
        """Export poetry.lock to a pip-compatible requirements.txt."""
        self.ensure_tools()
        cmd = [
            "poetry", "export",
            "-f", "requirements.txt",
            "-o", output,
            "--without-urls",
        ]
        if include_hashes:
            pass  # poetry export includes hashes by default
        else:
            cmd.append("--without-hashes")

        if env_name == "prod":
            cmd.extend(["--only", "main"])
        elif env_name == "dev":
            cmd.extend(["--with", "dev"])

        run_command(cmd, capture=False)
        logger.info("✅  Exported to %s", output)

    def verify(self) -> bool:
        """Check that poetry.lock is consistent with pyproject.toml."""
        self.ensure_tools()
        result = run_command(["poetry", "check", "--lock"], check=False)
        if result.returncode == 0:
            logger.info("✅  poetry.lock is consistent with pyproject.toml")
            return True
        logger.error("❌  poetry.lock is out of sync with pyproject.toml")
        return False


