# Strategy: pip freeze (simple but less robust)
# ---------------------------------------------------------------------------

class PipFreezeManager:
    """
    Simple strategy using `pip freeze` for environments where pip-tools or
    Poetry cannot be used.

    Workflow:
        1. Install desired packages in a virtualenv.
        2. Run `pip freeze` to capture exact versions.
        3. Optionally compute hashes for each package.
    """

    def __init__(self, config: ProjectConfig):
        self.config = config

    def freeze(self, output: str = "requirements.txt", include_hashes: bool = True):
        """Freeze current environment into a lock file."""
        result = run_command(
            [sys.executable, "-m", "pip", "freeze"],
            check=True,
        )

        lock = LockFile()
        python_version, platform = get_python_info()
        lock.python_version = python_version
        lock.platform = platform
        lock.generated_at = datetime.utcnow().isoformat() + "Z"

        for line in result.stdout.strip().splitlines():
            line = line.strip()
            if not line or line.startswith("#") or line.startswith("-"):
                continue
            match = re.match(r"^([A-Za-z0-9_.-]+)==(.+)$", line)
            if match:
                name, version = match.group(1), match.group(2)
                hashes = []
                if include_hashes:
                    hashes = self._get_package_hashes(name, version)
                dep = Dependency(name=name, version=version, hashes=hashes)
                lock.add(dep)

        write_requirements_txt(lock, output, include_hashes=include_hashes)

    def _get_package_hashes(self, name: str, version: str) -> List[str]:
        """Fetch hashes for a package version from PyPI."""
        try:
            import urllib.request
            url = f"https://pypi.org/pypi/{name}/{version}/json"
            with urllib.request.urlopen(url, timeout=10) as resp:
                data = json.loads(resp.read())
            hashes = []
            for file_info in data.get("urls", []):
                digests = file_info.get("digests", {})
                if "sha256" in digests:
                    hashes.append(f"sha256:{digests['sha256']}")
            return hashes
        except Exception as exc:
            logger.warning("Could not fetch hashes for %s==%s: %s", name, version, exc)
            return []

    def install(self, lock_file: str = "requirements.txt"):
        """Install from the frozen requirements file."""
        cmd = [sys.executable, "-m", "pip", "install", "-r", lock_file]
        if self.config.include_hashes:
            cmd.append("--require-hashes")
        run_command(cmd, capture=False)
        logger.info("✅  Installed from %s", lock_file)


