class DependencyAuditor:
    """
    Audit installed dependencies for known vulnerabilities using pip-audit
    or safety.
    """

    @staticmethod
    def audit_with_pip_audit(requirements_file: Optional[str] = None) -> bool:
        """Run pip-audit against the current environment or a requirements file."""
        if not tool_available("pip-audit"):
            logger.info("Installing pip-audit...")
            run_command(
                [sys.executable, "-m", "pip", "install", "pip-audit"],
                check=True,
            )

        cmd = ["pip-audit", "--strict"]
        if requirements_file and os.path.exists(requirements_file):
            cmd.extend(["-r", requirements_file])

        logger.info("Running security audit...")
        result = run_command(cmd, capture=False, check=False)
        if result.returncode == 0:
            logger.info("✅  No known vulnerabilities found.")
            return True
        else:
            logger.error("❌  Vulnerabilities detected! Review output above.")
            return False

    @staticmethod
    def check_outdated() -> List[Dict]:
        """List outdated packages."""
        result = run_command(
            [sys.executable, "-m", "pip", "list", "--outdated", "--format=json"],
            check=True,
        )
        outdated = json.loads(result.stdout)
        if outdated:
            logger.info("Outdated packages:")
            for pkg in outdated:
                logger.info(
                    "  %s: %s -> %s",
                    pkg["name"],
                    pkg["version"],
                    pkg["latest_version"],
                )
        else:
            logger.info("All packages are up to date.")
        return outdated


# ---------------------------------------------------------------------------
# Environment Diff / Drift Detection
# ---------------------------------------------------------------------------

class EnvironmentDiff:
    """Compare two lock files or environments to detect drift."""

    @staticmethod
    def diff_lock_files(file_a: str, file_b: str) -> Dict:
        """
        Compare two requirements.txt lock files and report differences.

        Returns a dict with keys: added, removed, changed.
        """
        lock_a = parse_requirements_txt(file_a)
        lock_b = parse_requirements_txt(file_b)

        names_a = set(lock_a.dependencies.keys())
        names_b = set(lock_b.dependencies.keys())

        added = names_b - names_a
        removed = names_a - names_b
        common = names_a & names_b

        changed = {}
        for name in common:
            dep_a = lock_a.dependencies[name]
            dep_b = lock_b.dependencies[name]
            if dep_a.version != dep_b.version:
                changed[name] = (dep_a.version, dep_b.version)

        result = {
            "added": {n: lock_b.dependencies[n].version for n in sorted(added)},
            "removed": {n: lock_a.dependencies[n].version for n in sorted(removed)},
            "changed": {
                n: {"from": v[0], "to": v[1]}
                for n, v in sorted(changed.items())
            },
        }

        # Pretty print
        if result["added"]:
            logger.info("➕ Added in %s:", file_b)
            for name, ver in result["added"].items():
                logger.info("    %s==%s", name, ver)

        if result["removed"]:
            logger.info("➖ Removed (only in %s):", file_a)
            for name, ver in result["removed"].items():
                logger.info("    %s==%s", name, ver)

        if result["changed"]:
            logger.info("🔄 Changed:")
            for name, versions in result["changed"].items():
                logger.info(
                    "    %s: %s -> %s", name, versions["from"], versions["to"]
                )

        if not any(result.values()):
            logger.info("✅  Lock files are identical.")

        return result


