class ProjectInitializer:
    """Initialize dependency management structure for a project."""

    @staticmethod
    def init_pip_tools(config: ProjectConfig):
        """Create the directory structure and template files for pip-tools."""
        os.makedirs("requirements", exist_ok=True)

        # Create prod.in
        prod_in = config.source_files.get("prod", "requirements/prod.in")
        if not os.path.exists(prod_in):
            with open(prod_in, "w") as fh:
                fh.write(
                    "# Direct production dependencies\n"
                    "# Add your production packages here, e.g.:\n"
                    "# requests>=2.28\n"
                    "# django>=4.2,<5.0\n"
                    "# sqlalchemy[asyncio]>=2.0\n"
                )
            logger.info("Created %s", prod_in)

        # Create dev.in (constrained against prod)
        dev_in = config.source_files.get("dev", "requirements/dev.in")
        if not os.path.exists(dev_in):
            prod_lock = config.lock_files.get("prod", "requirements/prod.txt")
            with open(dev_in, "w") as fh:
                fh.write(
                    f"# Development dependencies\n"
                    f"# Constrained against production lock file:\n"
                    f"-c {prod_lock}\n"
                    f"\n"
                    f"# Dev tools\n"
                    f"# pytest>=7.0\n"
                    f"# black\n"
                    f"# mypy\n"
                    f"# ruff\n"
                    f"# ipython\n"
                )
            logger.info("Created %s", dev_in)

        # Create test.in
        test_in = config.source_files.get("test", "requirements/test.in")
        if not os.path.exists(test_in):
            prod_lock = config.lock_files.get("prod", "requirements/prod.txt")
            with open(test_in, "w") as fh:
                fh.write(
                    f"# Test dependencies\n"
                    f"-c {prod_lock}\n"
                    f"\n"
                    f"# Testing\n"
                    f"# pytest>=7.0\n"
                    f"# pytest-cov\n"
                    f"# pytest-asyncio\n"
                    f"# factory-boy\n"
                    f"# responses\n"
                )
            logger.info("Created %s", test_in)

        config.save()
        logger.info("✅  pip-tools project structure initialized!")
        logger.info("")
        logger.info("Next steps:")
        logger.info("  1. Edit requirements/prod.in with your dependencies")
        logger.info("  2. Run: python dependency_lock_manager.py lock")
        logger.info("  3. Run: python dependency_lock_manager.py install --env dev")

    @staticmethod
    def init_poetry(config: ProjectConfig):
        """Initialize a Poetry project if pyproject.toml doesn't exist."""
        if not os.path.exists("pyproject.toml"):
            if tool_available("poetry"):
                run_command(["poetry", "init", "--no-interaction"], capture=False)
                logger.info("✅  Poetry project initialized!")
            else:
                logger.error("Poetry not found. Install it first.")
                return
        else:
            logger.info("pyproject.toml already exists.")

        config.save()
        logger.info("")
        logger.info("Next steps:")
        logger.info("  1. Add dependencies: poetry add <package>")
        logger.info("  2. Add dev dependencies: poetry add --group dev <package>")
        logger.info("  3. Run: python dependency_lock_manager.py lock")

    @staticmethod
    def init_pip_freeze(config: ProjectConfig):
        """Initialize simple pip freeze strategy."""
        config.lock_files = {
            "prod": "requirements.txt",
            "dev": "requirements-dev.txt",
            "test": "requirements-test.txt",
        }
        config.save()
        logger.info("✅  pip-freeze strategy configured.")
        logger.info("")
        logger.info("Next steps:")
        logger.info("  1. Install your packages in a virtualenv")
        logger.info("  2. Run: python dependency_lock_manager.py lock")

    @staticmethod
    def create_gitignore_entry():
        """Ensure lock files are NOT in .gitignore (they should be committed)."""
        gitignore = ".gitignore"
        note = (
            "\n# NOTE: DO NOT ignore lock files! They must be committed.\n"
            "# requirements/*.txt should be tracked in version control.\n"
            "# poetry.lock should be tracked in version control.\n"
        )
        if os.path.exists(gitignore):
            with open(gitignore) as fh:
                content = fh.read()
            if "lock files" not in content.lower():
                with open(gitignore, "a") as fh:
                    fh.write(note)

    @staticmethod
    def create_ci_workflow():
        """Generate a GitHub Actions workflow for dependency management."""
        workflow_dir = ".github/workflows"
        os.makedirs(workflow_dir, exist_ok=True)

        workflow = """name: Dependency Management

on:
  pull_request:
    paths:
      - 'requirements/**'
      - 'pyproject.toml'
      - 'poetry.lock'
  schedule:
    # Weekly dependency audit (Mondays at 9:00 UTC)
    - cron: '0 9 * * 1'

jobs:
  verify-lock:
    name: Verify Lock Files
    runs-on: ubuntu-latest
    steps:
      - uses: actions/checkout@v4
      - uses: actions/setup-python@v5
        with:
          python-version: '3.11'
      - name: Install tools
        run: pip install pip-tools pip-audit
      - name: Verify lock files are up to date
        run: |
          python dependency_lock_manager.py verify
      - name: Security audit
        run: |
          python dependency_lock_manager.py audit

  dependency-update:
    name: Check for Updates
    runs-on: ubuntu-latest
    if: github.event_name == 'schedule'
    steps:
      - uses: actions/checkout@v4
      - uses: actions/setup-python@v5
        with:
          python-version: '3.11'
      - name: Check outdated packages
        run: |
          pip install pip-tools
          python dependency_lock_manager.py lock --upgrade
          git diff --exit-code requirements/ || echo "::warning::Dependencies can be updated"
"""
        filepath = os.path.join(workflow_dir, "dependencies.yml")
        with open(filepath, "w") as fh:
            fh.write(workflow)
        logger.info("Created CI workflow: %s", filepath)


