class ScriptGenerator:
    """Generate helper scripts (Makefile, shell scripts) for common operations."""

    @staticmethod
    def generate_makefile(config: ProjectConfig):
        """Generate a Makefile with dependency management targets."""
        makefile_content = """# Dependency Management Targets
# Generated by dependency_lock_manager.py

.PHONY: deps-lock deps-install deps-install-prod deps-verify deps-audit deps-update deps-sync

PYTHON ?= python3
PIP_COMPILE ?= pip-compile
PIP_SYNC ?= pip-sync

# Lock all dependency files
deps-lock:
\t$(PYTHON) dependency_lock_manager.py lock

# Lock with upgrade (get latest versions)
deps-lock-upgrade:
\t$(PYTHON) dependency_lock_manager.py lock --upgrade

# Install dev dependencies
deps-install:
\t$(PYTHON) dependency_lock_manager.py install --env dev

# Install production dependencies only
deps-install-prod:
\t$(PYTHON) dependency_lock_manager.py install --env prod

# Verify lock files match installed packages
deps-verify:
\t$(PYTHON) dependency_lock_manager.py verify

# Run security audit
deps-audit:
\t$(PYTHON) dependency_lock_manager.py audit

# Update a specific package: make deps-update PKG=requests
deps-update:
\t$(PYTHON) dependency_lock_manager.py update $(PKG)

# Show differences between environments
deps-diff:
\t$(PYTHON) dependency_lock_manager.py diff prod dev
"""
        with open("Makefile.deps", "w") as fh:
            fh.write(makefile_content)
        logger.info("Generated Makefile.deps")
        logger.info("Include it in your main Makefile with: include Makefile.deps")


# ---------------------------------------------------------------------------
# Pre-commit Hook
# ---------------------------------------------------------------------------

class PreCommitHook:
    """Generate pre-commit hook configuration for dependency checks."""

    @staticmethod
    def generate_config():
        """Add dependency-related hooks to .pre-commit-config.yaml."""
        hook_content = """  # Dependency management hooks
  - repo: local
    hooks:
      - id: check-lock-files
        name: Check dependency lock files are up to date
        entry: python dependency_lock_manager.py verify
        language: python
        files: '(requirements/.*\\.in|pyproject\\.toml)$'
        pass_filenames: false
"""
        config_file = ".pre-commit-config.yaml"
        if os.path.exists(config_file):
            with open(config_file) as fh:
                content = fh.read()
            if "check-lock-files" not in content:
                with open(config_file, "a") as fh:
                    fh.write("\n" + hook_content)
                logger.info("Added dependency check hook to %s", config_file)
        else:
            with open(config_file, "w") as fh:
                fh.write("repos:\n" + hook_content)
            logger.info("Created %s with dependency check hook", config_file)


# ---------------------------------------------------------------------------
# Docker Integration Helper
# ---------------------------------------------------------------------------

class DockerHelper:
    """Generate Dockerfile snippets for dependency installation."""

    @staticmethod
    def generate_dockerfile_snippet(config: ProjectConfig) -> str:
        """Generate a multi-stage Dockerfile snippet with dependency caching."""
        snippet = '''# =============================================================================
# Dockerfile snippet for dependency installation
# Generated by dependency_lock_manager.py
# =============================================================================

# --- Builder stage: install dependencies ---
FROM python:3.11-slim AS builder

WORKDIR /app

# Install only production dependencies with hash verification
COPY requirements/prod.txt requirements/prod.txt
RUN pip install --no-cache-dir --require-hashes -r requirements/prod.txt

# --- Runtime stage ---
FROM python:3.11-slim AS runtime

WORKDIR /app

# Copy installed packages from builder
COPY --from=builder /usr/local/lib/python3.11/site-packages /usr/local/lib/python3.11/site-packages
COPY --from=builder /usr/local/bin /usr/local/bin

# Copy application code
COPY . .

# Verify dependencies
RUN pip check

CMD ["python", "-m", "your_app"]
'''
        filepath = "Dockerfile.deps"
        with open(filepath, "w") as fh:
            fh.write(snippet)
        logger.info("Generated %s", filepath)
        return snippet


# ---------------------------------------------------------------------------
# Main CLI
# ---------------------------------------------------------------------------

def build_parser() -> argparse.ArgumentParser:
    parser = argparse.ArgumentParser(
        description="Python Dependency Lock File Manager",
        formatter_class=argparse.RawDescriptionHelpFormatter,
        epilog="""
Examples:
  # Initialize a new project with pip-tools
  %(prog)s init --strategy pip-tools

  # Generate lock files for all environments
  %(prog)s lock

  # Update a specific package
  %(prog)s update requests

  # Install dev dependencies
  %(prog)s install --env dev

  # Run a security audit
  %(prog)s audit

  # Compare two lock files
  %(prog)s diff requirements/prod.txt requirements/dev.txt

  # Export lock file to another format
  %(prog)s export --format requirements

  # Generate helper scripts
  %(prog)s generate-scripts
        """,
    )
    parser.add_argument(
        "-v", "--verbose", action="store_true", help="Enable debug logging"
    )

    subparsers = parser.add_subparsers(dest="command", help="Command to run")

    # init
    init_parser = subparsers.add_parser("init", help="Initialize dependency management")
    init_parser.add_argument(
        "--strategy",
        choices=["pip-tools", "poetry", "pip-freeze"],
        default="pip-tools",
        help="Dependency management strategy (default: pip-tools)",
    )
    init_parser.add_argument(
        "--no-hashes",
        action="store_true",
        help="Disable hash generation in lock files",
    )

    # lock
    lock_parser = subparsers.add_parser("lock", help="Generate/update lock files")
    lock_parser.add_argument(
        "--env",
        choices=["prod", "dev", "test", "all"],
        default="all",
        help="Which environment to lock (default: all)",
    )
    lock_parser.add_argument(
        "--upgrade",
        action="store_true",
        help="Upgrade all packages to latest allowed versions",
    )

    # verify
    verify_parser = subparsers.add_parser(
        "verify", help="Verify installed packages match lock files"
    )
    verify_parser.add_argument(
        "--env", choices=["prod", "dev", "test"], default="prod"
    )

    # update
    update_parser = subparsers.add_parser("update", help="Update a specific package")
    update_parser.add_argument(
        "package", nargs="?", help="Package name to update (omit for all)"
    )
    update_parser.add_argument(
        "--env",
        choices=["prod", "dev", "test", "all"],
        default="all",
    )

    # install
    install_parser = subparsers.add_parser(
        "install", help="Install dependencies from lock files"
    )
    install_parser.add_argument(
        "--env",
        choices=["prod", "dev", "test"],
        default="dev",
        help="Environment to install (default: dev)",
    )

    # audit
    audit_parser = subparsers.add_parser(
        "audit", help="Run security audit on dependencies"
    )
    audit_parser.add_argument(
        "--check-outdated",
        action="store_true",
        help="Also check for outdated packages",
    )

    # diff
    diff_parser = subparsers.add_parser(
        "diff", help="Compare two lock files or environments"
    )
    diff_parser.add_argument("file_a", help="First lock file or environment name")
    diff_parser.add_argument("file_b", help="Second lock file or environment name")

    # export
    export_parser = subparsers.add_parser(
        "export", help="Export lock file to another format"
    )
    export_parser.add_argument(
        "--format",
        choices=["requirements", "poetry", "json"],
        default="requirements",
    )
    export_parser.add_argument("--output", "-o", default="requirements-exported.txt")
    export_parser.add_argument("--env", default="prod")

    # generate-scripts
    subparsers.add_parser(
        "generate-scripts",
        help="Generate Makefile, CI workflows, and Docker snippets",
    )

    # info
    subparsers.add_parser("info", help="Show current configuration and status")

    return parser


def cmd_init(args, config: ProjectConfig):
    config.strategy = Strategy(args.strategy)
    config.include_hashes = not args.no_hashes

    if config.strategy == Strategy.PIP_TOOLS:
        ProjectInitializer.init_pip_tools(config)
    elif config.strategy == Strategy.POETRY:
        ProjectInitializer.init_poetry(config)
    elif config.strategy == Strategy.PIP_FREEZE:
        ProjectInitializer.init_pip_freeze(config)

    ProjectInitializer.create_gitignore_entry()


def cmd_lock(args, config: ProjectConfig):
    if config.strategy == Strategy.PIP_TOOLS:
        mgr = PipToolsManager(config)
        if args.env == "all":
            mgr.compile_all(upgrade=args.upgrade)
        else:
            mgr.compile(args.env, upgrade=args.upgrade)
    elif config.strategy == Strategy.POETRY:
        mgr = PoetryManager(config)
        mgr.lock(update=args.upgrade)
    elif config.strategy == Strategy.PIP_FREEZE:
        mgr = PipFreezeManager(config)
        lock_file = config.lock_files.get(
            args.env if args.env != "all" else "prod",
            "requirements.txt",
        )
        mgr.freeze(output=lock_file, include_hashes=config.include_hashes)


def cmd_verify(args, config: ProjectConfig):
    if config.strategy == Strategy.PIP_TOOLS:
        mgr = PipToolsManager(config)
        success = mgr.verify(args.env)
    elif config.strategy == Strategy.POETRY:
        mgr = PoetryManager(config)
        success = mgr.verify()
    else:
        mgr = PipToolsManager(config)  # reuse parser logic
        success = mgr.verify(args.env)

    if not success:
        sys.exit(1)


def cmd_update(args, config: ProjectConfig):
    if config.strategy == Strategy.PIP_TOOLS:
        mgr = PipToolsManager(config)
        if args.env == "all":
            for env_name in ["prod", "dev", "test"]:
                if env_name in config.source_files:
                    mgr.compile(
                        env_name,
                        upgrade=not bool(args.package),
                        upgrade_package=args.package,
                    )
        else:
            mgr.compile(
                args.env,
                upgrade=not bool(args.package),
                upgrade_package=args.package,
            )
    elif config.strategy == Strategy.POETRY:
        mgr = PoetryManager(config)
        mgr.update(args.package)
    else:
        logger.info("For pip-freeze strategy, re-freeze your environment:")
        logger.info("  pip install --upgrade %s", args.package or "all-packages")
        logger.info("  python dependency_lock_manager.py lock")


def cmd_install(args, config: ProjectConfig):
    if config.strategy == Strategy.PIP_TOOLS:
        mgr = PipToolsManager(config)
        mgr.sync(args.env)
    elif config.strategy == Strategy.POETRY:
        mgr = PoetryManager(config)
        mgr.install(args.env)
    elif config.strategy == Strategy.PIP_FREEZE:
        mgr = PipFreezeManager(config)
        lock_file = config.lock_files.get(args.env, "requirements.txt")
        mgr.install(lock_file)


def cmd_audit(args, config: ProjectConfig):
    lock_file = config.lock_files.get("prod")
    success = DependencyAuditor.audit_with_pip_audit(lock_file)

    if hasattr(args, "check_outdated") and args.check_outdated:
        DependencyAuditor.check_outdated()

    if not success:
        sys.exit(1)


def cmd_diff(args, config: ProjectConfig):
    file_a = args.file_a
    file_b = args.file_b

    # Allow environment names instead of file paths
    if file_a in config.lock_files:
        file_a = config.lock_files[file_a]
    if file_b in config.lock_files:
        file_b = config.lock_files[file_b]

    if not os.path.exists(file_a):
        logger.error("File not found: %s", file_a)
        sys.exit(1)
    if not os.path.exists(file_b):
        logger.error("File not found: %s", file_b)
        sys.exit(1)

    EnvironmentDiff.diff_lock_files(file_a, file_b)


def cmd_export(args, config: ProjectConfig):
    if config.strategy == Strategy.POETRY:
        mgr = PoetryManager(config)
        include_hashes = config.include_hashes
        mgr.export_requirements(
            output=args.output,
            include_hashes=include_hashes,
            env_name=args.env,
        )
    else:
        lock_file = config.lock_files.get(args.env, "requirements.txt")
        if args.format == "json":
            lock = parse_requirements_txt(lock_file)
            data = {
                dep.name: {
                    "version": dep.version,
                    "hashes": dep.hashes,
                }
                for dep in lock.sorted_deps
            }
            with open(args.output, "w") as fh:
                json.dump(data, fh, indent=2)
            logger.info("Exported to %s", args.output)
        else:
            # Just copy the lock file
            import shutil
            shutil.copy2(lock_file, args.output)
            logger.info("Exported %s -> %s", lock_file, args.output)


def cmd_generate_scripts(args, config: ProjectConfig):
    ScriptGenerator.generate_makefile(config)
    ProjectInitializer.create_ci_workflow()
    DockerHelper.generate_dockerfile_snippet(config)
    PreCommitHook.generate_config()
    logger.info("✅  All helper scripts generated!")


def cmd_info(args, config: ProjectConfig):
    python_version, platform = get_python_info()
    print("=" * 60)
    print("Dependency Lock Manager — Project Info")
    print("=" * 60)
    print(f"Strategy:        {config.strategy.value}")
    print(f"Python:          {python_version}")
    print(f"Platform:        {platform}")
    print(f"Include Hashes:  {config.include_hashes}")
    print(f"Allow Prereleases: {config.allow_prereleases}")
    print()
    print("Source Files:")
    for env_name, path in config.source_files.items():
        exists = "✅" if os.path.exists(path) else "❌"
        print(f"  {env_name:10s}: {path} {exists}")
    print()
    print("Lock Files:")
    for env_name, path in config.lock_files.items():
        exists = "✅" if os.path.exists(path) else "❌"
        count = ""
        if os.path.exists(path):
            lock = parse_requirements_txt(path)
            count = f"({len(lock.dependencies)} packages)"
        print(f"  {env_name:10s}: {path} {exists} {count}")
    print()

    # Check tool availability
    print("Tools:")
    for tool in ["pip-compile", "pip-sync", "pip-audit", "poetry", "safety"]:
        available = "✅" if tool_available(tool) else "❌"
        print(f"  {tool:15s}: {available}")
    print("=" * 60)


def main():
    parser = build_parser()
    args = parser.parse_args()

    if args.verbose:
        logging.getLogger().setLevel(logging.DEBUG)

    if not args.command:
        parser.print_help()
        sys.exit(0)

    config = ProjectConfig.load()

    command_map = {
        "init": cmd_init,
        "lock": cmd_lock,
        "verify": cmd_verify,
        "update": cmd_update,
        "install": cmd_install,
        "audit": cmd_audit,
        "diff": cmd_diff,
        "export": cmd_export,
        "generate-scripts": cmd_generate_scripts,
        "info": cmd_info,
    }

    handler = command_map.get(args.command)
    if handler:
        try:
            handler(args, config)
        except Exception as exc:
            logger.error("Error: %s", exc)
            if args.verbose:
                import traceback
                traceback.print_exc()
            sys.exit(1)
    else:
        parser.print_help()
        sys.exit(1)


if __name__ == "__main__":
    main()